import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as e,f as s}from"./app-7cfa41e7.js";const i={},t=s(`<h2 id="shiro" tabindex="-1"><a class="header-anchor" href="#shiro" aria-hidden="true">#</a> Shiro</h2><ol><li>Apache Shiro是Java的一个安全(权限)框架</li><li>Shiro 可以轻松的完成:身份认证、授权、加密、会话管理等</li><li>Shiro可以使用在JavaSE、JavaEE</li><li>功能强大且易用,可以快速轻松地保护任务应用程序</li></ol><h2 id="功能" tabindex="-1"><a class="header-anchor" href="#功能" aria-hidden="true">#</a> 功能</h2><ol><li><p>Authentication</p><p>身份认证/登录,验证用户是不是拥有相应的身份</p></li><li><p>Authorization</p><p>授权,即权限验证,验证某个已认证的用户是否拥有某个权限;即判断用户是否能进行什么操作,如:验证某个用户是否拥有某个角色;或者细粒度的验证某个用户是否对某个资源是否某个权限</p></li><li><p>Session Manager</p><p>会话管理,即用户登录后就是一次会话,在没有退出前,它的所有信息都在会话中;会话开业是普通的JavaSE环境,也可以是Web环境</p></li><li><p>Cryptography</p><p>加密,巴欧数据的安全性,如密码加密存储到数据库,而不是明文存储</p></li><li><p>Web Support</p><p>Web支持,非常容易的集成Web环境;</p></li><li><p>Caching</p><p>缓存,比如用户登录后,其用户信息、拥有的角色/权限不必每次去查,可以提高效率</p></li><li><p>Concurrency</p><p>支持多线程并发验证</p></li><li><p>Testing</p><p>测试</p></li><li><p>“Run As&quot;</p><p>用另外用户身份</p></li><li><p>Remember Me</p><p>记住我</p></li></ol><h2 id="原理" tabindex="-1"><a class="header-anchor" href="#原理" aria-hidden="true">#</a> 原理</h2><ol><li><h3 id="shiro架构-外部" tabindex="-1"><a class="header-anchor" href="#shiro架构-外部" aria-hidden="true">#</a> Shiro架构(外部)</h3><p>首先是一个应用程序要和Shiro进行交互,那么传递的对象就是Subject(也就是当前用户或可以是对象)，然后会传入到ShiroSecurityManager(也就是安全管理器)使用各种工具(组件)，然后Shiro通过Realm(数据源)获取数据进行安全校验</p></li><li><h3 id="内部" tabindex="-1"><a class="header-anchor" href="#内部" aria-hidden="true">#</a> 内部</h3><p>内部主要是各种管理器</p></li></ol><h2 id="基本使用" tabindex="-1"><a class="header-anchor" href="#基本使用" aria-hidden="true">#</a> 基本使用</h2><p>shrio可以使用数据库,也可以使用ini类型的文件</p><h2 id="登录认证" tabindex="-1"><a class="header-anchor" href="#登录认证" aria-hidden="true">#</a> 登录认证</h2><p>要说登录认证,那么肯定要知道是什么登录认证</p><ol><li><h3 id="概念" tabindex="-1"><a class="header-anchor" href="#概念" aria-hidden="true">#</a> 概念</h3><ol><li>初始化获取SecurityManager</li><li>获取Subject对象</li><li>创建token,web应用用户名密码从页面传递</li><li>完成登录</li></ol></li><li><h3 id="登录认证基本流程" tabindex="-1"><a class="header-anchor" href="#登录认证基本流程" aria-hidden="true">#</a> 登录认证基本流程</h3><ol><li>收集用户身份/凭证,例如用户名/密码</li><li>调用Subject.login进行登录,如果失败将得到响应的AuthenticationException异常,根据异常提示用户错误信息,否则登录成功</li><li>创建自定义的Realm类,继承AuthorizingRealm类,实现doGetAuthticationInfo()方法</li></ol></li></ol><h2 id="角色和授权" tabindex="-1"><a class="header-anchor" href="#角色和授权" aria-hidden="true">#</a> 角色和授权</h2><ol><li><p>授权：访问控制,在授权中需要了解几个关键对象:主体,资源,权限,角色</p></li><li></li><li><p>授权流程：</p><ol><li>首先调用Subject.isPermitted*/hasRole接口，其会委托给SecurityManager,而SecurityManager接着会委托给Authorizer;</li><li>Authorizer是真正的授权者,如果调用isPermitted(&quot;user:view&quot;),其首先会通过PermissionResolver把字符串转换成相应的Permission实例</li><li>在尽显授权之前，其会调用相应的Realm获取Subject相应的角色/权限用于匹配传入的角色/权限</li><li>Authorizer会判断Realm的角色/权限是否和传入的匹配,如果有多个Realm，会委托ModularRealmAuthorizer进行循环判断,如果匹配如isPermitted/hasRole会返回true,否则返回false表示授权失败</li></ol></li></ol><h2 id="shiro加密" tabindex="-1"><a class="header-anchor" href="#shiro加密" aria-hidden="true">#</a> Shiro加密</h2><h2 id="shiro自定义登录认证" tabindex="-1"><a class="header-anchor" href="#shiro自定义登录认证" aria-hidden="true">#</a> Shiro自定义登录认证</h2><h2 id="shiro整合springboot" tabindex="-1"><a class="header-anchor" href="#shiro整合springboot" aria-hidden="true">#</a> Shiro整合SpringBoot</h2><h2 id="登录认证实现" tabindex="-1"><a class="header-anchor" href="#登录认证实现" aria-hidden="true">#</a> 登录认证实现</h2><h2 id="多个realm的认证策略设置" tabindex="-1"><a class="header-anchor" href="#多个realm的认证策略设置" aria-hidden="true">#</a> 多个realm的认证策略设置</h2><ol><li><p>多个realm实现原理</p><p>当程序配置多个Realm时候,例如用户名密码,手机号验证码校验</p></li></ol><p>​ AuthenticationStrategy是一个无状态的组件,它在身份验证尝试中被询问4次(这4次交互所需的任何必要的状态将被作为方法参数)</p><p>① 在所有 Realm 被调用之前</p><p>② 在调用 Realm 的 getAuthenticationInfo 方法之前</p><p>③ 在调用 Realm 的 getAuthenticationInfo 方法之后</p><p>④ 在所有 Realm 被调用之后</p><p>认证策略的另外一项工作就是聚合所有 Realm 的结果信息封装至一个AuthenticationInfo 实例中，并将此信息返回，以此作为 Subject 的身份信息。</p><p>Shiro 中定义了 3 种认证策略的实现：<br><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/f1a468af89ff374901ec81b1ca95de8a.png" alt="img" loading="lazy"></p><p>ModularRealmAuthenticator 内置的认证策略默认实现是 AtLeastOneSuccessfulStrategy 方式。可以通过配置修改策略。</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@Bean</span>
<span class="token keyword">public</span> <span class="token class-name">DefaultWebSecurityManager</span> <span class="token function">defaultWebSecurityManager</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span> 
<span class="token comment">//1 创建  defaultWebSecurityManager 对象</span>
    <span class="token class-name">DefaultWebSecurityManager</span> defaultWebSecurityManager <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DefaultWebSecurityManager</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">//2 创建认证对象，并设置认证策略</span>
    <span class="token class-name">ModularRealmAuthenticator</span> modularRealmAuthenticator <span class="token operator">=</span> <span class="token keyword">new</span> 
<span class="token class-name">ModularRealmAuthenticator</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    modularRealmAuthenticator<span class="token punctuation">.</span><span class="token function">setAuthenticationStrategy</span><span class="token punctuation">(</span><span class="token keyword">new</span> 
<span class="token class-name">AllSuccessfulStrategy</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    defaultWebSecurityManager<span class="token punctuation">.</span><span class="token function">setAuthenticator</span><span class="token punctuation">(</span>modularRealmAuthenticator<span class="token punctuation">)</span> 
<span class="token punctuation">;</span>
<span class="token comment">//3 封装  myRealm 集合</span>
    <span class="token class-name">List</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">Realm</span><span class="token punctuation">&gt;</span></span> list <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ArrayList</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
    list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>myRealm<span class="token punctuation">)</span><span class="token punctuation">;</span>
    list<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span>myRealm2<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">//4 将 myRealm 存入 defaultWebSecurityManager 对象</span>
    defaultWebSecurityManager<span class="token punctuation">.</span><span class="token function">setRealms</span><span class="token punctuation">(</span>list<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">//5 返回</span>
    <span class="token keyword">return</span> defaultWebSecurityManager<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="remember-me功能" tabindex="-1"><a class="header-anchor" href="#remember-me功能" aria-hidden="true">#</a> Remember me功能</h2><ol><li>基本流程</li></ol><h2 id="角色认证" tabindex="-1"><a class="header-anchor" href="#角色认证" aria-hidden="true">#</a> 角色认证</h2><h2 id="权限验证" tabindex="-1"><a class="header-anchor" href="#权限验证" aria-hidden="true">#</a> 权限验证</h2><h2 id="异常处理" tabindex="-1"><a class="header-anchor" href="#异常处理" aria-hidden="true">#</a> 异常处理</h2><p>使用@ControllerAdvice和@ExceptionHandler实现特殊异常处理</p><h2 id="前端页面授权验证" tabindex="-1"><a class="header-anchor" href="#前端页面授权验证" aria-hidden="true">#</a> 前端页面授权验证</h2><h2 id="缓存工具ehcache" tabindex="-1"><a class="header-anchor" href="#缓存工具ehcache" aria-hidden="true">#</a> 缓存工具EhCache</h2><h2 id="会话管理" tabindex="-1"><a class="header-anchor" href="#会话管理" aria-hidden="true">#</a> 会话管理</h2><ol><li><p>SessionManager</p><p>会话管理器</p></li></ol>`,38),l=[t];function o(p,r){return n(),e("div",null,l)}const d=a(i,[["render",o],["__file","shiro.html.vue"]]);export{d as default};
